SET search_path TO bank_r2_005;
CREATE TABLE customers (customer_id integer PRIMARY KEY, customer_name text NOT NULL);
CREATE TABLE accounts (account_id integer PRIMARY KEY, customer_id integer NOT NULL REFERENCES customers(customer_id), account_name text NOT NULL, currency text NOT NULL CHECK (currency IN ('GBP','USD')), account_status text NOT NULL CHECK (account_status IN ('active','closed','frozen')));
CREATE TABLE account_holds (hold_id integer PRIMARY KEY, account_id integer NOT NULL REFERENCES accounts(account_id), amount_cents integer NOT NULL, hold_state text NOT NULL CHECK (hold_state IN ('pending','released','expired')));
CREATE TABLE ledger_transactions (ledger_transaction_id integer PRIMARY KEY, external_transaction_id text NOT NULL UNIQUE, state text NOT NULL CHECK (state IN ('pending','posted','reversed','failed')), currency text NOT NULL CHECK (currency IN ('GBP','USD')));
CREATE TABLE ledger_entries (ledger_entry_id integer PRIMARY KEY, ledger_transaction_id integer NOT NULL REFERENCES ledger_transactions(ledger_transaction_id), account_id integer NOT NULL REFERENCES accounts(account_id), side text NOT NULL CHECK (side IN ('debit','credit')), amount_cents integer NOT NULL CHECK (amount_cents > 0));
CREATE TABLE transfer_requests (transfer_id integer PRIMARY KEY, from_account_id integer NOT NULL REFERENCES accounts(account_id), to_account_id integer NOT NULL REFERENCES accounts(account_id), amount_cents integer NOT NULL, currency text NOT NULL CHECK (currency IN ('GBP','USD')), request_state text NOT NULL CHECK (request_state IN ('posted','pending','failed','conflict','reversed')), ledger_transaction_id integer REFERENCES ledger_transactions(ledger_transaction_id));
CREATE TABLE idempotency_keys (key_id integer PRIMARY KEY, idempotency_key text NOT NULL UNIQUE, request_fingerprint text NOT NULL, transfer_id integer REFERENCES transfer_requests(transfer_id), key_state text NOT NULL CHECK (key_state IN ('active','failed','conflict')));
CREATE TABLE transfer_attempts (attempt_id integer PRIMARY KEY, idempotency_key text NOT NULL, request_fingerprint text NOT NULL, attempt_state text NOT NULL CHECK (attempt_state IN ('created','duplicate_returned','conflict','failed_retryable')), transfer_id integer REFERENCES transfer_requests(transfer_id));
CREATE TABLE transaction_events (event_id integer PRIMARY KEY, external_transaction_id text NOT NULL, transfer_id integer REFERENCES transfer_requests(transfer_id), event_state text NOT NULL CHECK (event_state IN ('pending','posted','failed','reversed')), amount_cents integer NOT NULL, event_at timestamp NOT NULL);
CREATE TABLE reversals (reversal_id integer PRIMARY KEY, original_ledger_transaction_id integer NOT NULL REFERENCES ledger_transactions(ledger_transaction_id), reversal_ledger_transaction_id integer NOT NULL REFERENCES ledger_transactions(ledger_transaction_id), reason text NOT NULL);
